  "trad-0": {"prompt":"Traducir: '¡Buen provecho!' (antes de comer)","promptNative":"¡Buen provecho! (se dice antes de comer)"},
  "trad-1": {"prompt":"Traducir: '¡Buena suerte!' (lit. 'ni pluma ni pelusa')","promptNative":"¡Buena suerte!"},
  "trad-2": {"prompt":"Traducir: 'No importa / no es nada grave.'","promptNative":"No importa, no es nada grave."},
  "trad-3": {"prompt":"Traducir: 'Hizo el ridículo.'","promptNative":"Hizo el ridículo."},
  "trad-4": {"prompt":"Traducir: 'Son idénticos, como dos gotas de agua.'","promptNative":"Son idénticos, como dos gotas de agua."},
  "trad-5": {"prompt":"Traducir: 'Está diciendo puras mentiras.'","promptNative":"Está mintiendo descaradamente."},
  "trad-6": {"prompt":"Traducir: 'Cuando las ranas críen pelo.' (es decir, nunca)","promptNative":"Cuando las ranas críen pelo (nunca)."},
  "trad-7": {"prompt":"Traducir: 'Estás haciendo una montaña de un grano de arena.'","promptNative":"Haces una montaña de un grano de arena."},
  "trad-8": {"prompt":"Traducir: 'Me quedé muerto de miedo.'","promptNative":"Me quedé muerto de miedo."},
  "trad-9": {"prompt":"Traducir: 'Está ahí sentado sin hacer nada.'","promptNative":"Está sin hacer nada."},
  "trad-10": {"prompt":"Traducir: 'hacer un trabajo de cualquier manera / a la ligera'","promptNative":"hacer algo de cualquier manera"},
  "trad-11": {"prompt":"Traducir: 'Lo difícil es empezar.' (refrán)","promptNative":"Lo difícil es empezar."},
  "trad-12": {"prompt":"Traducir: 'inventar la rueda'","promptNative":"inventar la rueda"},
  "trad-13": {"prompt":"Traducir: 'Ojos que no ven, corazón que no siente.'","promptNative":"Ojos que no ven, corazón que no siente."},
  "trad-14": {"prompt":"Traducir: '¡Buenos días!'","promptNative":"¡Buenos días!"},
  "trad-15": {"prompt":"Traducir: '¡Feliz cumpleaños!'","promptNative":"¡Feliz cumpleaños!"},
  "trad-16": {"prompt":"Traducir: '¡Que te mejores pronto!'","promptNative":"¡Que te mejores pronto!"},
  "trad-17": {"prompt":"Traducir: 'Siéntete como en tu casa.'","promptNative":"Siéntete como en tu casa."},
  "trad-18": {"prompt":"Traducir: '¡Sírvete!' (la comida)","promptNative":"¡Sírvete! (la comida)"},
  "trad-19": {"prompt":"Traducir: '¡Salud!' (un brindis)","promptNative":"¡Salud! (brindis)"},
  "trad-20": {"prompt":"Traducir: '¡Felicidades!'","promptNative":"¡Felicidades!"},
  "trad-21": {"prompt":"Traducir: 'matar dos pájaros de un tiro'","promptNative":"matar dos pájaros de un tiro"},
  "trad-22": {"prompt":"Traducir: 'No es oro todo lo que reluce.'","promptNative":"No es oro todo lo que reluce."},
