  "trad-26": {"prompt":"Traducir: 'Mira antes de saltar.'","promptNative":"Mira antes de saltar."},
  "trad-27": {"prompt":"Traducir: 'No se puede complacer a todos.'","promptNative":"No se puede complacer a todos."},
  "trad-28": {"prompt":"Traducir: 'Hablando del rey de Roma.'","promptNative":"Hablando del rey de Roma."},
  "trad-29": {"prompt":"Traducir: 'A quien madruga, Dios lo ayuda.'","promptNative":"A quien madruga, Dios lo ayuda."},
